# Skeptic: only packet-taught patterns; explicit I/O contract
def assess(record: dict) -> str:
    required = {'branch_count', 'known_steps', 'agent_success', 'baseline_success', 'case_id', 'tool_choice_uncertain'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    if record.get('known_steps') not in (None, False, 0, "", set(), [], {}):
        return 'PASS'
    return 'REJECT'

valid = {"case_id": 'CASO-SYN-1A', 'known_steps': True, 'branch_count': 1, 'tool_choice_uncertain': True, 'baseline_success': True, 'agent_success': True}
adverse = {"case_id": 'CASO-SYN-1A-ADV', 'known_steps': False, 'branch_count': 0, 'tool_choice_uncertain': False, 'baseline_success': False, 'agent_success': False}
missing = {k: valid[k] for k in valid if k != 'agent_success'}
print(assess(valid))
print(assess(adverse))
print(assess(missing))

